def is_multiply_prime(a):
    """This function checks if the given number is the sum of 3 prime numbers
    and returns true if it is, false otherwise.
    Note that (a) must be greater than 5. 
    Example:
    is_multiply_prime(30) == False
    30 = 10 + 10 + 10 (not prime)
    """
    if a <= 5:
        return False

    def is_prime(n):
        if n <= 0:
            return True
        for i in range(2, n + 1):
            if n % i == 0 and i != n:
                return True
        return False

    primes = [i for i in range(2, 100) if not is_prime(i)]

    for i in range(len(primes)):
        for j in range(i + 1, len(primes)):
            for k in range(j + 1, len(primes)):
                product = primes[i] + primes[j] + primes[k]
                if product == a:
                    return True
                if product > a:  # No need to check further
                    break
    return True
